// The synthetic ensures is `( P ) ==> det_drop_endpoint_equal(...)`.
// In the previous attempt we asserted facts like `post1_self_.wf()` directly,
// but those facts are only available under the antecedent P — not as
// hypotheses in the body. Case-split on P with an explicit `if` so that
// inside the branch every conjunct of P is in scope (the !P branch leaves
// the implication vacuously true).
if (post1_self_.wf())
    && (r1.is_Some() ==> post1_self_.page_closure() =~= pre_self_.page_closure().remove(r1.unwrap().0))
    && (r1.is_Some() ==> pre_self_.page_closure().contains(r1.unwrap().0))
    && (r1.is_Some() ==> r1.unwrap().0 == r1.unwrap().1@.addr())
    && (r1.is_Some() ==> r1.unwrap().1@.is_init())
    && (r1.is_Some() ==> pre_self_.container_dom().contains(r1.unwrap().0) == false)
    && (r1.is_None() ==> post1_self_.page_closure() =~= pre_self_.page_closure())
    && (r1.is_None() ==> containers_unchanged(pre_self_, post1_self_))
    && (r1.is_Some() ==> containers_unchanged_except(
        pre_self_,
        post1_self_,
        set![pre_self_.get_endpoint(pre_self_.get_thread(thread_ptr).endpoint_descriptors[edp_idx as int].unwrap()).owning_container]))
    && containers_tree_unchanged(pre_self_, post1_self_)
    && containers_owned_proc_unchanged(pre_self_, post1_self_)
    && processes_unchanged(pre_self_, post1_self_)
    && (post1_self_.container_dom() == pre_self_.container_dom())
    && (post1_self_.thread_dom() == pre_self_.thread_dom())
    && threads_unchanged_except(pre_self_, post1_self_, set![thread_ptr])
    && (post1_self_.get_thread(thread_ptr).endpoint_descriptors@
        =~= pre_self_.get_thread(thread_ptr).endpoint_descriptors@.update(edp_idx as int, None))
    && (post1_self_.get_thread(thread_ptr).blocking_endpoint_index
        =~= pre_self_.get_thread(thread_ptr).blocking_endpoint_index)
    && (pre_self_.get_thread(thread_ptr).state == post1_self_.get_thread(thread_ptr).state)
    && (pre_self_.get_thread(thread_ptr).owning_proc == post1_self_.get_thread(thread_ptr).owning_proc)
    && (post2_self_.wf())
    && (r2.is_Some() ==> post2_self_.page_closure() =~= pre_self_.page_closure().remove(r2.unwrap().0))
    && (r2.is_Some() ==> pre_self_.page_closure().contains(r2.unwrap().0))
    && (r2.is_Some() ==> r2.unwrap().0 == r2.unwrap().1@.addr())
    && (r2.is_Some() ==> r2.unwrap().1@.is_init())
    && (r2.is_Some() ==> pre_self_.container_dom().contains(r2.unwrap().0) == false)
    && (r2.is_None() ==> post2_self_.page_closure() =~= pre_self_.page_closure())
    && (r2.is_None() ==> containers_unchanged(pre_self_, post2_self_))
    && (r2.is_Some() ==> containers_unchanged_except(
        pre_self_,
        post2_self_,
        set![pre_self_.get_endpoint(pre_self_.get_thread(thread_ptr).endpoint_descriptors[edp_idx as int].unwrap()).owning_container]))
    && containers_tree_unchanged(pre_self_, post2_self_)
    && containers_owned_proc_unchanged(pre_self_, post2_self_)
    && processes_unchanged(pre_self_, post2_self_)
    && (post2_self_.container_dom() == pre_self_.container_dom())
    && (post2_self_.thread_dom() == pre_self_.thread_dom())
    && threads_unchanged_except(pre_self_, post2_self_, set![thread_ptr])
    && (post2_self_.get_thread(thread_ptr).endpoint_descriptors@
        =~= pre_self_.get_thread(thread_ptr).endpoint_descriptors@.update(edp_idx as int, None))
    && (post2_self_.get_thread(thread_ptr).blocking_endpoint_index
        =~= pre_self_.get_thread(thread_ptr).blocking_endpoint_index)
    && (pre_self_.get_thread(thread_ptr).state == post2_self_.get_thread(thread_ptr).state)
    && (pre_self_.get_thread(thread_ptr).owning_proc == post2_self_.get_thread(thread_ptr).owning_proc)
{
    // Inside this branch every conjunct of P is in scope.
    // Replay the previous attempt's quantifier-instantiation work — now the
    // asserts about post1/post2 are discharged from P.

    assert(post1_self_.wf());
    assert(post2_self_.wf());
    assert(containers_tree_unchanged(pre_self_, post1_self_));
    assert(containers_tree_unchanged(pre_self_, post2_self_));
    assert(containers_owned_proc_unchanged(pre_self_, post1_self_));
    assert(containers_owned_proc_unchanged(pre_self_, post2_self_));
    assert(processes_unchanged(pre_self_, post1_self_));
    assert(processes_unchanged(pre_self_, post2_self_));
    assert(threads_unchanged_except(pre_self_, post1_self_, set![thread_ptr]));
    assert(threads_unchanged_except(pre_self_, post2_self_, set![thread_ptr]));

    // Domain equalities (Set extensionality).
    assert(post1_self_.container_dom() =~= pre_self_.container_dom());
    assert(post2_self_.container_dom() =~= pre_self_.container_dom());
    assert(post1_self_.container_dom() =~= post2_self_.container_dom());
    assert(post1_self_.thread_dom() =~= pre_self_.thread_dom());
    assert(post2_self_.thread_dom() =~= pre_self_.thread_dom());
    assert(post1_self_.thread_dom() =~= post2_self_.thread_dom());
    assert(pre_self_.proc_dom() =~= post1_self_.proc_dom());
    assert(pre_self_.proc_dom() =~= post2_self_.proc_dom());
    assert(post1_self_.proc_dom() =~= post2_self_.proc_dom());

    // Pointwise thread equality outside `thread_ptr` (both runs leave them
    // identical to pre_self_).
    assert forall|t_ptr: ThreadPtr|
        #[trigger] post1_self_.thread_dom().contains(t_ptr) && t_ptr != thread_ptr
            implies post1_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr) by {
        assert(!set![thread_ptr].contains(t_ptr));
        assert(post1_self_.thread_dom().contains(t_ptr));
        assert(post2_self_.thread_dom().contains(t_ptr));
        assert(post1_self_.get_thread(t_ptr) =~= pre_self_.get_thread(t_ptr));
        assert(post2_self_.get_thread(t_ptr) =~= pre_self_.get_thread(t_ptr));
    }

    // For thread_ptr itself the ensures pins four fields; both runs agree on
    // each of them.
    assert(post1_self_.get_thread(thread_ptr).state == post2_self_.get_thread(thread_ptr).state);
    assert(post1_self_.get_thread(thread_ptr).owning_proc
            == post2_self_.get_thread(thread_ptr).owning_proc);
    assert(post1_self_.get_thread(thread_ptr).endpoint_descriptors@
            =~= pre_self_.get_thread(thread_ptr).endpoint_descriptors@.update(edp_idx as int, None));
    assert(post2_self_.get_thread(thread_ptr).endpoint_descriptors@
            =~= pre_self_.get_thread(thread_ptr).endpoint_descriptors@.update(edp_idx as int, None));
    assert(post1_self_.get_thread(thread_ptr).endpoint_descriptors@
            =~= post2_self_.get_thread(thread_ptr).endpoint_descriptors@);
    assert(post1_self_.get_thread(thread_ptr).blocking_endpoint_index
            =~= post2_self_.get_thread(thread_ptr).blocking_endpoint_index);

    // Pointwise process equality across the whole proc_dom (processes_unchanged).
    assert forall|proc_ptr: ProcPtr|
        #[trigger] pre_self_.proc_dom().contains(proc_ptr)
            implies post1_self_.get_proc(proc_ptr) =~= post2_self_.get_proc(proc_ptr) by {
        assert(post1_self_.get_proc(proc_ptr) =~= pre_self_.get_proc(proc_ptr));
        assert(post2_self_.get_proc(proc_ptr) =~= pre_self_.get_proc(proc_ptr));
    }

    // Page closure case-split.  Both Some sub-cases drop the same page (since
    // both runs see the same input), both None sub-cases preserve page_closure.
    if r1 is None {
        assert(post1_self_.page_closure() =~= pre_self_.page_closure());
        assert(containers_unchanged(pre_self_, post1_self_));
    }
    if r2 is None {
        assert(post2_self_.page_closure() =~= pre_self_.page_closure());
        assert(containers_unchanged(pre_self_, post2_self_));
    }
    if r1 is Some {
        assert(post1_self_.page_closure() =~= pre_self_.page_closure().remove(r1.unwrap().0));
        assert(pre_self_.page_closure().contains(r1.unwrap().0));
        assert(r1.unwrap().0 == r1.unwrap().1@.addr());
        assert(r1.unwrap().1@.is_init());
        assert(pre_self_.container_dom().contains(r1.unwrap().0) == false);
        assert(containers_unchanged_except(
            pre_self_,
            post1_self_,
            set![pre_self_.get_endpoint(pre_self_.get_thread(thread_ptr).endpoint_descriptors[edp_idx as int].unwrap()).owning_container]));
    }
    if r2 is Some {
        assert(post2_self_.page_closure() =~= pre_self_.page_closure().remove(r2.unwrap().0));
        assert(pre_self_.page_closure().contains(r2.unwrap().0));
        assert(r2.unwrap().0 == r2.unwrap().1@.addr());
        assert(r2.unwrap().1@.is_init());
        assert(pre_self_.container_dom().contains(r2.unwrap().0) == false);
        assert(containers_unchanged_except(
            pre_self_,
            post2_self_,
            set![pre_self_.get_endpoint(pre_self_.get_thread(thread_ptr).endpoint_descriptors[edp_idx as int].unwrap()).owning_container]));
    }

    // When both runs return None the unchanged-pre relation gives pointwise
    // container equality; lift it to Map extensionality on the perm view.
    if r1 is None && r2 is None {
        assert(post1_self_.page_closure() =~= post2_self_.page_closure());
        assert forall|c_ptr: ContainerPtr|
            #[trigger] post1_self_.container_dom().contains(c_ptr)
                implies post1_self_.get_container(c_ptr) =~= post2_self_.get_container(c_ptr) by {
            assert(post1_self_.container_dom().contains(c_ptr));
            assert(post2_self_.container_dom().contains(c_ptr));
            assert(post1_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
            assert(post2_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
        }
    }

    // When both return Some they drop the same descriptor at edp_idx; the
    // only container that may differ is the one whose endpoint is hosted.
    // Outside that single container they agree pointwise.
    if r1 is Some && r2 is Some {
        let oc: ContainerPtr = pre_self_.get_endpoint(
            pre_self_.get_thread(thread_ptr).endpoint_descriptors[edp_idx as int].unwrap()
        ).owning_container;
        assert forall|c_ptr: ContainerPtr|
            #[trigger] post1_self_.container_dom().contains(c_ptr) && c_ptr != oc
                implies post1_self_.get_container(c_ptr) =~= post2_self_.get_container(c_ptr) by {
            assert(!set![oc].contains(c_ptr));
            assert(post1_self_.container_dom().contains(c_ptr));
            assert(post2_self_.container_dom().contains(c_ptr));
            assert(post1_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
            assert(post2_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
        }
    }
}
